oldWay:
/* Three separate rules for the same style */
h2 a,
h3 a,
h4 a {
  color: #a855f7;
}

/* Gets messier with context prefixes */
.post h2 a,
.post h3 a,
.post h4 a {
  text-decoration: none;
}

modernWay:
:is(h2, h3, h4) a {
  color: #a855f7;
}

.post :is(h2, h3, h4) a {
  text-decoration: none;
}

startingCSS:
.post {
  padding: 1.5rem;
  background: #1e293b;
  border-radius: 10px;
  color: #e2e8f0;
  max-width: 500px;
  font-size: 0.9rem;
  line-height: 1.6;
}

.post h2, .post h3 {
  margin: 0 0 0.5rem;
}

.post a {
  color: #e2e8f0;
  text-decoration: none;
}

.post p a {
  color: #94a3b8;
  text-decoration: underline;
}

